const rows = $input.all();
const rawData = rows.map(r => r.json);

const grouped = {};
for (const row of rawData) {
  const key = `${row['Product ID']}||${row['Region']}`;
  if (!grouped[key]) {
    grouped[key] = {
      product_id: row['Product ID'],
      category:   row['Category'],
      region:     row['Region'],
      store_id:   row['Store ID'],
      data_points: []
    };
  }
  grouped[key].data_points.push({
    date:               row['Date'],
    inventory_level:    parseFloat(row['Inventory Level'])    || 0,
    units_sold:         parseFloat(row['Units Sold'])         || 0,
    units_ordered:      parseFloat(row['Units Ordered'])      || 0,
    price:              parseFloat(row['Price'])              || 0,
    discount:           parseFloat(row['Discount'])           || 0,
    weather_condition:  row['Weather Condition']              || '',
    promotion:          parseInt(row['Promotion'])            || 0,
    competitor_pricing: parseFloat(row['Competitor Pricing']) || 0,
    seasonality:        row['Seasonality']                    || '',
    epidemic:           parseInt(row['Epidemic'])             || 0,
    demand:             parseFloat(row['Demand'])             || 0
  });
}

const avg = arr => arr.length ? arr.reduce((a,b)=>a+b,0)/arr.length : 0;
const max = arr => arr.length ? Math.max(...arr) : 0;
const min = arr => arr.length ? Math.min(...arr) : 0;

const enriched = Object.values(grouped).map(group => {
  const pts = group.data_points;
  const n   = pts.length;
  const demands          = pts.map(p => p.demand);
  const unitsSold        = pts.map(p => p.units_sold);
  const prices           = pts.map(p => p.price);
  const competitorPrices = pts.map(p => p.competitor_pricing);
  const discounts        = pts.map(p => p.discount);
  const inventories      = pts.map(p => p.inventory_level);

  const third    = Math.max(1, Math.floor(n / 3));
  const firstAvg = avg(demands.slice(0, third));
  const lastAvg  = avg(demands.slice(-third));
  const trend    = lastAvg > firstAvg * 1.05 ? 'increasing'
                 : lastAvg < firstAvg * 0.95 ? 'decreasing' : 'stable';

  const weatherCounts = {};
  pts.forEach(p => { weatherCounts[p.weather_condition] = (weatherCounts[p.weather_condition]||0)+1; });
  const seasonCounts = {};
  pts.forEach(p => { seasonCounts[p.seasonality] = (seasonCounts[p.seasonality]||0)+1; });

  const avg_price      = parseFloat(avg(prices).toFixed(2));
  const avg_comp_price = parseFloat(avg(competitorPrices).toFixed(2));

  return {
    product_id:  group.product_id,
    category:    group.category,
    region:      group.region,
    store_id:    group.store_id,
    data_points_count: n,
    date_range:  { from: pts[0]?.date, to: pts[n-1]?.date },
    demand_stats: {
      avg:   parseFloat(avg(demands).toFixed(2)),
      max:   max(demands),
      min:   min(demands),
      total: demands.reduce((a,b)=>a+b,0),
      trend
    },
    sales_stats: {
      avg_units_sold:   parseFloat(avg(unitsSold).toFixed(2)),
      avg_inventory:    parseFloat(avg(inventories).toFixed(2)),
      avg_discount_pct: parseFloat(avg(discounts).toFixed(2)),
      stockout_risk:    avg(inventories) < avg(unitsSold) * 1.2 ? 'high' : 'low'
    },
    pricing: {
      avg_price,
      avg_competitor_price: avg_comp_price,
      price_vs_competitor: avg_comp_price
        ? ((avg_price - avg_comp_price) / avg_comp_price * 100).toFixed(1) + '%'
        : 'n/a'
    },
    contextual_signals: {
      promotion_rate_pct:  parseFloat((pts.filter(p=>p.promotion===1).length/n*100).toFixed(1)),
      epidemic_rate_pct:   parseFloat((pts.filter(p=>p.epidemic===1).length/n*100).toFixed(1)),
      weather_breakdown:   weatherCounts,
      season_breakdown:    seasonCounts
    }
  };
});

// Pass config forward alongside grouped data
const config = $node['Sub-workflow Trigger'].json;
return [{ json: { ...config, total_groups: enriched.length, groups: enriched } }];

const data = $input.first().json;

// Group the product groups by region
const byRegion = {};
for (const group of data.groups) {
  const region = group.region;
  if (!byRegion[region]) byRegion[region] = [];
  byRegion[region].push(group);
}

// Return one item per region
return Object.entries(byRegion).map(([region, groups]) => ({
  json: {
    region,
    groups,
    total_groups: groups.length
  }
}));

return $input.all().map(input => {
  const data = input.json;

  const systemMessage = `Demand forecasting analyst. Return raw JSON only, no markdown.
Schema: {"forecast_date":"<ISO>","forecasts":[{"product_id":"","category":"","region":"","historical_avg_demand":0,"historical_trend":"","predicted_demand":0,"confidence":"","confidence_reason":"","key_drivers":[],"stockout_risk":"","recommended_action":"","action_detail":""}]}`;

  const userPrompt = `Forecast ${data.region} region, ${data.total_groups} products. JSON only.
${JSON.stringify(data.groups)}`;

  return {
    json: {
      systemMessage,
      userPrompt,
      region:       data.region,
      total_groups: data.total_groups
    }
  };
});

return $input.all().flatMap(input => {
  const data = input.json;

  const slimGroups = data.groups.map(g => ({
    pid:    g.product_id,
    cat:    g.category,
    reg:    g.region,
    n:      g.data_points_count,
    d_avg:  g.demand_stats.avg,
    d_max:  g.demand_stats.max,
    d_min:  g.demand_stats.min,
    trend:  g.demand_stats.trend,
    inv:    g.sales_stats.avg_inventory,
    sold:   g.sales_stats.avg_units_sold,
    risk:   g.sales_stats.stockout_risk,
    disc:   g.sales_stats.avg_discount_pct,
    pvc:    g.pricing.price_vs_competitor,
    promo:  g.contextual_signals.promotion_rate_pct,
    season: Object.keys(g.contextual_signals.season_breakdown)[0] || ''
  }));

  // Split into chunks of 10
  const chunkSize = 5;
  const chunks = [];
  for (let i = 0; i < slimGroups.length; i += chunkSize) {
    chunks.push(slimGroups.slice(i, i + chunkSize));
  }

  return chunks.map((chunk, idx) => ({
    json: {
      region:       data.region,
      total_groups: chunk.length,
      groups:       chunk,
      batch_label:  `${data.region}-${idx + 1}`
    }
  }));
});

return $input.all().flatMap(input => {
  const response = input.json;

  // Ilmu.ai OpenAI-compatible format
  let rawText = response.choices?.[0]?.message?.content || '';

  if (!rawText) {
    throw new Error('No text in response. Keys: ' + Object.keys(response).join(', '));
  }

  // Strip markdown fences just in case
  rawText = rawText
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  let parsed;
  try {
    parsed = JSON.parse(rawText);
  } catch(e) {
    throw new Error('Parse failed: ' + e.message + '\nRaw: ' + rawText.substring(0, 300));
  }

  if (!parsed.forecasts?.length) return [];

  return parsed.forecasts.map(f => ({
    json: {
      run_id:                $('Sub-workflow Trigger').first().json.runId || $execution.id,
      forecast_date:         parsed.forecast_date || new Date().toISOString().split('T')[0],
      product_id:            f.product_id,
      category:              f.category,
      region:                f.region,
      historical_avg_Demand: f.historical_avg_demand,
      historical_trend:      f.historical_trend,
      predicted_demand:      f.predicted_demand,
      confidence:            f.confidence,
      confidence_reason:     f.confidence_reason,
      key_drivers:           Array.isArray(f.key_drivers) ? f.key_drivers.join(', ') : f.key_drivers || '',
      stockout_risk:         f.stockout_risk,
      recomended_action:     f.recommended_action,
      action_detail:         f.action_detail
    }
  }));
});

// Read forecast data from the validation node
const forecasts = $('Parse for Sheets').all().map(i => i.json);
const runId = $execution.id || '';

// Build region breakdown
const byRegion = {};
const stockoutRisk = [];
for (const f of forecasts) {
  byRegion[f.region] = (byRegion[f.region] || 0) + 1;
  if (f.stockout_risk === 'high') stockoutRisk.push(`${f.product_id} (${f.region})`);
}

return [{ json: {
  wf1_status:          'success',
  run_id:              runId,
  completed_at:        new Date().toISOString(),
  forecasts_generated: forecasts.length,
  regions_covered:     Object.keys(byRegion),
  breakdown:           byRegion,
  stockout_risks:      stockoutRisk.length,
  written_to_sheet:    true,
  summary_message:     `WF-1 complete: generated ${forecasts.length} forecasts across ${Object.keys(byRegion).length} regions, flagged ${stockoutRisk.length} stockout risks.`
}}];
